#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

#ifdef RD_WG_SIZE_0_0
        #define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
        #define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
        #define BLOCK_SIZE RD_WG_SIZE
#else
        #define BLOCK_SIZE 16
#endif

void lud_omp(float *m, int matrix_dim)
{
    int i, j, k, offset;
    float sum;
    float shadow[BLOCK_SIZE][BLOCK_SIZE];
    float dia[BLOCK_SIZE][BLOCK_SIZE];
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];
    int array_offset, idx, global_row_id, global_col_id;

    for (offset = 0; offset < matrix_dim - BLOCK_SIZE; offset += BLOCK_SIZE) {
        // lud_diagonal equivalent
        #pragma omp parallel for private(i, j, array_offset, idx) shared(m, shadow, offset, matrix_dim)
        for (idx = 0; idx < BLOCK_SIZE; idx++) {
            array_offset = offset * matrix_dim + offset;
            for (i = 0; i < BLOCK_SIZE; i++) {
                shadow[i][idx] = m[array_offset + idx];
                array_offset += matrix_dim;
            }

            for (i = 0; i < BLOCK_SIZE - 1; i++) {
                if (idx > i) {
                    for (j = 0; j < i; j++)
                        shadow[idx][i] -= shadow[idx][j] * shadow[j][i];
                    shadow[idx][i] /= shadow[i][i];
                }

                if (idx > i) {
                    for (j = 0; j < i + 1; j++)
                        shadow[i + 1][idx] -= shadow[i + 1][j] * shadow[j][idx];
                }
            }

            array_offset = (offset + 1) * matrix_dim + offset;
            for (i = 1; BLOCK_SIZE > i; i++) {
                m[array_offset + idx] = shadow[i][idx];
                array_offset += matrix_dim;
            }
        }

        // lud_perimeter equivalent
        #pragma omp parallel for private(i, j, array_offset, idx) shared(m, dia, peri_row, peri_col, offset, matrix_dim)
        for (idx = 0; idx < BLOCK_SIZE * 2; idx++) {
            if (idx < BLOCK_SIZE) {
                array_offset = offset * matrix_dim + offset;
                for (i = 0; BLOCK_SIZE / 2 > i; i++) {
                    dia[i][idx] = m[array_offset + idx];
                    array_offset += matrix_dim;
                }

                array_offset = offset * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    peri_row[i][idx] = m[array_offset + (offset / BLOCK_SIZE + 1) * BLOCK_SIZE + idx];
                    array_offset += matrix_dim;
                }

                for (i = 1; BLOCK_SIZE > i; i++) {
                    for (j = 0; i > j; j++)
                        peri_row[i][idx] -= dia[i][j] * peri_row[j][idx];
                }

                array_offset = (offset + 1) * matrix_dim + offset;
                for (i = 1; BLOCK_SIZE > i; i++) {
                    m[array_offset + (offset / BLOCK_SIZE + 1) * BLOCK_SIZE + idx] = peri_row[i][idx];
                    array_offset += matrix_dim;
                }
            } else {
                int local_idx = idx - BLOCK_SIZE;
                array_offset = (offset + BLOCK_SIZE / 2) * matrix_dim + offset;
                for (i = BLOCK_SIZE / 2; BLOCK_SIZE > i; i++) {
                    dia[i][local_idx] = m[array_offset + local_idx];
                    array_offset += matrix_dim;
                }

                array_offset = (offset + (offset / BLOCK_SIZE + 1) * BLOCK_SIZE) * matrix_dim + offset;
                for (i = 0; BLOCK_SIZE > i; i++) {
                    peri_col[local_idx][i] = m[array_offset + local_idx];
                    array_offset += matrix_dim;
                }

                for (i = 0; BLOCK_SIZE > i; i++) {
                    for (j = 0; i > j; j++)
                        peri_col[local_idx][i] -= peri_col[local_idx][j] * dia[j][i];
                    peri_col[local_idx][i] /= dia[i][i];
                }

                array_offset = (offset + (offset / BLOCK_SIZE + 1) * BLOCK_SIZE) * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    m[array_offset + local_idx] = peri_col[i][local_idx];
                    array_offset += matrix_dim;
                }
            }
        }

        // lud_internal equivalent
        #pragma omp parallel for private(i, sum, global_row_id, global_col_id) shared(m, peri_row, peri_col, offset, matrix_dim)
        for (global_row_id = offset + BLOCK_SIZE; global_row_id < matrix_dim; global_row_id += BLOCK_SIZE) {
            for (global_col_id = offset + BLOCK_SIZE; global_col_id < matrix_dim; global_col_id += BLOCK_SIZE) {
                for (i = 0; i < BLOCK_SIZE; i++) {
                    for (j = 0; j < BLOCK_SIZE; j++) {
                        peri_row[i][j] = m[(offset + i) * matrix_dim + global_col_id + j];
                        peri_col[i][j] = m[(global_row_id + i) * matrix_dim + offset + j];
                    }
                }

                for (i = 0; i < BLOCK_SIZE; i++) {
                    for (j = 0; j < BLOCK_SIZE; j++) {
                        sum = 0;
                        for (k = 0; k < BLOCK_SIZE; k++)
                            sum += peri_col[i][k] * peri_row[k][j];
                        m[(global_row_id + i) * matrix_dim + global_col_id + j] -= sum;
                    }
                }
            }
        }
    }

    // Final diagonal block
    offset = matrix_dim - BLOCK_SIZE;
    #pragma omp parallel for private(i, j, array_offset, idx) shared(m, shadow, offset, matrix_dim)
    for (idx = 0; idx < BLOCK_SIZE; idx++) {
        array_offset = offset * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE; i++) {
            shadow[i][idx] = m[array_offset + idx];
            array_offset += matrix_dim;
        }

        for (i = 0; i < BLOCK_SIZE - 1; i++) {
            if (idx > i) {
                for (j = 0; j < i; j++)
                    shadow[idx][i] -= shadow[idx][j] * shadow[j][i];
                shadow[idx][i] /= shadow[i][i];
            }

            if (idx > i) {
                for (j = 0; j < i + 1; j++)
                    shadow[i + 1][idx] -= shadow[i + 1][j] * shadow[j][idx];
            }
        }

        array_offset = (offset + 1) * matrix_dim + offset;
        for (i = 1; BLOCK_SIZE > i; i++) {
            m[array_offset + idx] = shadow[i][idx];
            array_offset += matrix_dim;
        }
    }
}
